targets.rawSql:
SELECT close AS last_close
FROM v_bars_1min
WHERE dataname = ${ticker:sqlstring}
  AND source IN ('ALOR', 'MOEX_ISS_FALLBACK')
ORDER BY ts DESC, CASE WHEN source = 'ALOR' THEN 0 ELSE 1 END
LIMIT 1;

SELECT EXTRACT(EPOCH FROM ts) * 1000 AS last_update_ms
FROM v_bars_1min
WHERE dataname = ${ticker:sqlstring}
  AND source IN ('ALOR', 'MOEX_ISS_FALLBACK')
ORDER BY ts DESC, CASE WHEN source = 'ALOR' THEN 0 ELSE 1 END
LIMIT 1;
